"""Batch translations 276-400 for Distinction III."""

BATCH: dict[int, dict] = {
276: {"nativeDefinition": "To make someone feel uncomfortable or disturbed.", "japaneseMeaning": "（人を）気持ち悪がらせる", "etymology": "weird out（変にする）が不快感を与えるスラング。", "examples": {"B": "コニーが昨夜キッチンで急に踊り始めたの、君も気持ち悪かった？", "C": "青信号が気持ち悪い。いつも黄色だと思ってる。", "D": "誰かを不快にさせる。"}},
277: {"nativeDefinition": "To end a relationship with someone.", "japaneseMeaning": "（人と）縁を切る", "etymology": "cut ties（絆を切る）が関係を断つことを表す。", "examples": {"B": "ピートが突然縁を切った理由がわからない。コーヒーこぼしたのか、スカーフのせいか。", "C": "ジョシュとは縁を切った。彼女の誕生日サプライズをバラした。2ヶ月準備してたのに。", "D": "誰かとの関係を終わらせる。"}},
278: {"nativeDefinition": "To have a grudge or ill will toward someone.", "japaneseMeaning": "（人に）意地悪する、恨みを持つ", "etymology": "have it in for（〜に対して持っている）が悪意を表す。", "examples": {"B": "また怒られた。ポールが意地悪してる理由わかる？先週話したら親友みたいに言ってた。", "C": "怒鳴られるだけで意地悪してるとは言えない。", "D": "嫌いまたは恨みを持つ。"}},
279: {"nativeDefinition": "A person who appears friendly but is actually an rival.", "japaneseMeaning": "フレネミー、友敵", "etymology": "frenemy（friend＋enemy）が友達のふりをする敵。", "examples": {"B": "アイスクリームはフレネミー。美味しいけど太る。", "C": "大学の友達のパーティー行く予定だけど、行きたくない。どっちかというとフレネミー。何て断ろう？", "D": "友達のふりをする敵。"}},
280: {"nativeDefinition": "Forgetful or not paying attention.", "japaneseMeaning": "抜けている、うっかり屋", "etymology": "absent-minded（心が不在）が注意力散漫を表す。", "examples": {"B": "最近かなり抜けてる。老眼のせいかな。", "C": "すごく抜けてる。20分スマホ探した。目の前にあった。", "D": "不注意な。"}},
281: {"nativeDefinition": "An imagination that exaggerates or creates unrealistic fears.", "japaneseMeaning": "想像力豊かすぎる、大げさな想像", "etymology": "overactive imagination（過剰に活動する想像力）が空想過多を表す。", "examples": {"B": "想像力豊かすぎて暗闘が怖い。影に何か隠れてると思っちゃう。", "C": "あの雲、ドラゴンに見えない？想像力豊かすぎか。", "D": "物事を大げさに想像する想像力。"}},
282: {"nativeDefinition": "To publicly boycott or reject someone.", "japaneseMeaning": "（人を）キャンセルする、追放する", "etymology": "cancel（キャンセルする）がSNS時代の追放を表す。", "examples": {"B": "このコメディアン、キャンセルされて魂の救済の旅に出てる。あまり効果ないと思う。", "C": "ひどい性差別コメントが限界。彼をキャンセルする。", "D": "誰かを追放する。"}},
283: {"nativeDefinition": "A dominant, confident leader (especially among men).", "japaneseMeaning": "アルファ、支配的な人", "etymology": "alpha（アルファ）が動物の社会性から転じた支配的な人。", "examples": {"B": "アルファオスだと言いふらしても、アルファにはなれない。行動が全て。", "C": "ジョシュは賢く自信があって勇気があって女性にモテる。間違いなくアルファ。", "D": "支配的な人。"}},
284: {"nativeDefinition": "To advance through promotions in a company.", "japaneseMeaning": "出世する、コーポレートラダーを登る", "etymology": "corporate ladder（企業のはしご）が昇進の階段を表す。", "examples": {"B": "出世に夢中だったけど、長男が生まれて人生には仕事以外もあると気づいた。", "C": "父は選択肢は2つだと言った。出世するか、自分のビジネスを作るか。数週間考えて辞めた。", "D": "昇進を通じて会社で進む。"}},
285: {"nativeDefinition": "The most effective or recommended way to do something.", "japaneseMeaning": "ベストプラクティス、最善の方法", "etymology": "best practice（最良の実践）が業界標準の方法を表す。", "examples": {"B": "米は炊く前に洗うのがベストプラクティスだけど、面倒でやらない。", "C": "ミニマリズムのベストプラクティスを学びたいならこの動画見て。", "D": "理想的なプロセス。"}},
286: {"nativeDefinition": "To do something without real effort or enthusiasm.", "japaneseMeaning": "形だけやる、やらされ仕事", "etymology": "go through the motions（動作を通す）が形だけの行為を表す。", "examples": {"B": "来週退職だから、今は形だけやってる。上司が喜ぶかどうかもうどうでもいい。", "C": "成功する選手は練習で形だけやることはない。", "D": "あまり努力せずに何かをする。"}},
287: {"nativeDefinition": "An attractive older man with gray hair.", "japaneseMeaning": "シルバーフォックス、白髪のイケオジ", "etymology": "silver fox（銀色のキツネ）が白髪の魅力的な男性を表す。", "examples": {"B": "今の人生目標は、セクシーで話上手なシルバーフォックスになること。", "C": "この写真で父がシルバーフォックスに見えるって言うけど、会ったらがっかりするよ。", "D": "ハンサムな年配の男性。"}},
288: {"nativeDefinition": "Not while someone is in charge or responsible.", "japaneseMeaning": "（私が）見てる限りはダメ", "etymology": "not on one's watch（自分の見張り中ではない）が責任者として阻止する表現。", "examples": {"B": "母が好きなぬいぐるみ捨てるところだった。見てる限りはダメ。", "C": "私が責任者の間、性差別的なコメントは許さない。", "D": "誰かが責任者の間は。"}},
289: {"nativeDefinition": "To be unaware of realities outside one's own experience.", "japaneseMeaning": "世間知らず、バブルの中にいる", "etymology": "live in a bubble（泡の中に住む）が閉じた世界にいることを表す。", "examples": {"B": "この街にホームレスがいないと思ってるなんて、本当にバブルの中にいる。", "C": "去年世界旅行して、ずっとバブルの中に生きてたと気づいた。目覚めの時。", "D": "自分の世界しか知らない。"}},
290: {"nativeDefinition": "High expectations to meet from a predecessor.", "japaneseMeaning": "大きな靴を履く、高い期待", "etymology": "big shoes to fill（埋める大きな靴）が前任者の大きな足跡を表す。", "examples": {"B": "父が引退して会社を引き継いだ。大きな靴を履くけど、なんとか水の上を歩けてる。", "C": "お疲れ様、次の仕事頑張って。会社に大きく貢献した。後任は大きな靴を履くことになる。", "D": "満たすべき高い期待。"}},
291: {"nativeDefinition": "To reset and start fresh.", "japaneseMeaning": "リセットボタンを押す、再スタートする", "etymology": "hit the reset button（リセットボタンを押す）が再出発を表す。", "examples": {"B": "ロックダウンは最悪だけど、人生の多くの部分をリセットする機会になった。", "C": "かなり疲れてるから、休暇行ってリセットしよう。", "D": "やり直す。"}},
292: {"nativeDefinition": "Nothing compares to something; it's the best.", "japaneseMeaning": "（〜に）勝るものはない", "etymology": "there's nothing like（〜のようなものはない）が最高であることを表す。", "examples": {"B": "バック・トゥ・ザ・フューチャーは最高。勝るものはない。10代で見て衝撃だった。", "C": "海の音と新鮮なコーヒーの香りで目覚める。勝るものはない。", "D": "何かが最高である。"}},
293: {"nativeDefinition": "Something that makes you cry emotionally.", "japaneseMeaning": "泣ける、涙腺崩壊", "etymology": "tear-jerker（涙を引き出すもの）が感動的な作品を表す。", "examples": {"B": "この映画、すごく泣ける。なぜかわからない。音楽かも。", "C": "この本、本当に泣ける。読むたびに感情が動く。", "D": "涙を誘発するもの。"}},
294: {"nativeDefinition": "Used to understate or soften a statement.", "japaneseMeaning": "控えめに言えば、遠慮なく言うと", "etymology": "to put it mildly（穏やかに言えば）が控えめな表現を表す。", "examples": {"B": "彼のパフォーマンスは、控えめに言ってもがっかり。", "C": "控えめに言っても、昨夜のコンサートは最高だった。", "D": "控えめに言えば。"}},
295: {"nativeDefinition": "To admire someone excessively.", "japaneseMeaning": "（人を）神格化する、崇拝する", "etymology": "put on a pedestal（台座の上に置く）が過度な崇拝を表す。", "examples": {"B": "僕を神格化しないで。ただの意見だから、間違ってるかも。", "C": "金持ちで有名だからって神格化して、過去のひどい行いを見逃すな。", "D": "誰かを崇拝する。"}},
296: {"nativeDefinition": "Not suited for a particular role or activity.", "japaneseMeaning": "（〜向きじゃない）才能がない", "etymology": "not cut out to（切り出されていない）が適性がないことを表す。", "examples": {"B": "外科医向きじゃないと思う。血を見るたびにパニック。", "C": "彼はパイロット向きじゃない。高所恐怖症だから。", "D": "〜するのに向いていない。"}},
297: {"nativeDefinition": "A person who prefers to be alone.", "japaneseMeaning": "一匹狼", "etymology": "lone wolf（一匹の狼）が単独行動を好む人を表す。", "examples": {"B": "一匹狼だからって人嫌いじゃない。一人の時間が好きなだけ。", "C": "彼女、本当の一匹狼。誰かとランチしてるとこ見たことない。", "D": "一人が好きな人。"}},
298: {"nativeDefinition": "Everything has a cost; nothing is truly free.", "japaneseMeaning": "タダより高いものはない", "etymology": "no free lunch（無料のランチなし）が経済学の格言。", "examples": {"B": "無条件でiPhone無料？絶対詐欺。タダより高いものはない。", "C": "成功は運じゃなく努力の結果。タダより高いものはない。", "D": "価値あるものにタダはない。"}},
299: {"nativeDefinition": "Suffering is necessary to achieve results.", "japaneseMeaning": "ノーペイン・ノーゲイン", "etymology": "no pain no gain（痛みなしに得なし）がフィットネスの格言。", "examples": {"B": "結婚式のスーツに合わせるため3週間チキンとブロッコリーだけ。ノーペイン・ノーゲイン。", "C": "ハイキングで膝ボロボロだけど、頂上の景色は最高。ノーペイン・ノーゲイン。", "D": "達成には苦しみが必要。"}},
300: {"nativeDefinition": "An acceptable cost for a worthwhile benefit.", "japaneseMeaning": "（〜は）小さな代償", "etymology": "a small price to pay（払う小さな代償）が許容できるコストを表す。", "examples": {"B": "日本のタクシー料金高いけど、この美しい国に住む小さな代償。", "C": "ダウンジャケット少しバカみたいだけど、暖かさの小さな代償。", "D": "許容できるコスト。"}},
301: {"nativeDefinition": "To establish something firmly.", "japaneseMeaning": "（地位などを）確固たるものにする", "etymology": "cement（セメント）が比喩的に固めることを表す。", "examples": {"B": "この映画で彼は僕のお気に入りの俳優として確固たる地位を築いた。", "C": "金メダルで世界最高の野球チームとしての地位を確固たるものにした。", "D": "何かをしっかり確立する。"}},
302: {"nativeDefinition": "To encounter an unexpected problem.", "japaneseMeaning": "（問題に）ぶつかる、つまずく", "etymology": "hit a snag（障害物にぶつかる）が予期せぬ問題を表す。", "examples": {"B": "車貸してくれる？問題にぶつかって、解決できそう。", "C": "来週オーストラリア旅行の予定だったけど、ビザ申請でつまずいた。", "D": "予期せぬ問題に遭遇する。"}},
303: {"nativeDefinition": "Firmly established and difficult to change.", "japaneseMeaning": "根深い", "etymology": "deep-rooted（深く根付いた）が長年の固定観念を表す。", "examples": {"B": "女の子に好かれてると言われても信じない。根深い不信感がある。", "C": "ジェンダーバイアスはこの国にまだ根深い。多くは無意識。", "D": "しっかりと根付いている。"}},
304: {"nativeDefinition": "By or in itself; intrinsically.", "japaneseMeaning": "それ自体は、厳密には", "etymology": "per se（それ自体で）がラテン語由来の「厳密に言えば」。", "examples": {"B": "仕事自体は嫌いじゃない。一緒に働く人が問題。", "C": "犬嫌いというわけじゃない、厳密には。猫が本当に嫌い。", "D": "正確には。"}},
305: {"nativeDefinition": "Expressing regret about missed opportunities (woulda, shoulda, coulda).", "japaneseMeaning": "〜すればよかった", "etymology": "woulda shoulda coulda（would have, should have, could have）が後悔の口語。", "examples": {"B": "もっとビットコイン投資すればよかった。", "C": "大学時代お金全部酒に使わず貯えればよかった。", "D": "後悔。"}},
306: {"nativeDefinition": "A long, complicated series of events.", "japaneseMeaning": "長話、一大事件", "etymology": "saga（サガ＝叙事詩）が長い物語を表す。", "examples": {"B": "今朝の通勤、一大事件だった。ランチで全部話す。", "C": "家族全員でのクリスmasディナー、いつも一大事件。全員動員しても時間と労力がかかる。", "D": "長く複雑な話。"}},
307: {"nativeDefinition": "To become more sociable and confident.", "japaneseMeaning": "殻から出る、外向的になる", "etymology": "come out of one's shell（殻から出る）が内向的な人が開放的になることを表す。", "examples": {"B": "昔はもっとシャイだったけど、バスケが殻から出るのに役立った。", "C": "内向的なのが嫌。今年はもっと殻から出て新しい人に会いたい。", "D": "もっと社交的になる。"}},
308: {"nativeDefinition": "To argue about minor, unimportant details.", "japaneseMeaning": "細かいことにこだわる", "etymology": "split hairs（毛を分ける）が些細な違いにこだわることを表す。", "examples": {"B": "細部は大事だけど、ロゴが1ピクセルズレてるって細かいことにこだわりすぎ。誰が気づく？", "C": "政治家が細かいことにこだわって、本質的な問題に触れないのがイライラする。", "D": "小さな詳細にうるさすぎる。"}},
309: {"nativeDefinition": "Setting something aside; apart from.", "japaneseMeaning": "〜はさておき", "etymology": "aside（脇に）が本題から除外することを表す。", "examples": {"B": "離婚の話はさておき、アンドリューは僕の質問にほぼ全部答えてくれる。いい人。", "C": "守備はさておき、ジョーは非常に知的な選手。", "D": "〜を除いて。"}},
310: {"nativeDefinition": "A situation with roughly equal chances.", "japaneseMeaning": "五分五分、運次第", "etymology": "coin-flip（コイン投げ）が50%の確率を表す。", "examples": {"B": "来年東京と大阪どちらに住むか、まだ五分五分。", "C": "投資は長期でやるべき。デイトレードは五分五分に近い。", "D": "不確実な状況。"}},
311: {"nativeDefinition": "A hypothetical scenario used to explore an idea.", "japaneseMeaning": "思考実験", "etymology": "thought experiment（思考実験）が仮定の状況で考える方法。", "examples": {"B": "ちょっとした思考実験。1万ドル20%の確率か、確実に1000ドル、どっち？僕は前者。", "C": "無人島に3つ持っていくものは？面白い思考実験。", "D": "仮説的な質問。"}},
312: {"nativeDefinition": "Directly; confronting something without avoidance.", "japaneseMeaning": "正面から、真っ向から", "etymology": "head-on（正面から）が直接対峙することを表す。", "examples": {"B": "気候変動問題を解決するには、各国が協力して正面から取り組むしかない。", "C": "問題を避けると不安が増えるから、バンドエイドを剥がして正面から向き合う方が好き。", "D": "直接。"}},
313: {"nativeDefinition": "Having a close enough relationship to use first names.", "japaneseMeaning": "（〜と）名前で呼び合う仲", "etymology": "on a first name basis（名前の呼び合いの関係）が親しい関係を表す。", "examples": {"B": "待って、どうやって金正恩と名前で呼び合う仲になったの？スパイ？", "C": "アリアナ・グランデと名前で呼び合う仲になるのが目標。マジで。", "D": "親しい関係にある。"}},
314: {"nativeDefinition": "Still active and doing well.", "japaneseMeaning": "今も健在、まだ生きている", "etymology": "alive and kicking（生きて蹴っている）が健在を表す。", "examples": {"B": "人種差別は今も世界中で健在。ただ隠すのが上手くなっただけ。", "C": "メイクはまだ存在するけど、健在と言うのは言い過ぎ。", "D": "活発に存在する。"}},
315: {"nativeDefinition": "And similar things; et cetera.", "japaneseMeaning": "〜などなど", "etymology": "what-not（何とか）が「など」を表す口語。", "examples": {"B": "ラップトップがウイルスだらけで起動しない。寿命かも。", "C": "アドレナリンが好き。スカイダイビング、バンジージャンプなどなど。", "D": "など。"}},
316: {"nativeDefinition": "As the proverb or saying goes.", "japaneseMeaning": "ことわざにもあるように", "etymology": "as the saying goes（ことわざが言うように）が格言の引用。", "examples": {"B": "まだ勝ってないのに祝ってる。ことわざにもあるように、取らぬ狸の皮算用。", "C": "来年南米をバックパックで旅する。ことわざにもあるように、旅にお金を使うと豊かになる。", "D": "格言が言うように。"}},
317: {"nativeDefinition": "Even unreliable things can occasionally be correct.", "japaneseMeaning": "時計が止まったものも二度正しい", "etymology": "broken clock is right twice a day（壊れた時計も1日2回正しい）のことわざ。", "examples": {"B": "キャストの株価予測が今回は当たった。壊れた時計も二度正しい。", "C": "彼の言うことほとんどデタラメ。たまに正しいこともある。時計が止まっても二度正しい。", "D": "普段当てになない人でも時々正しい。"}},
318: {"nativeDefinition": "Always late for everything.", "japaneseMeaning": "いつも遅刻する、時間感覚ゼロ", "etymology": "late for one's own funeral（自分の葬式に遅刻する）が極端な遅刻を表す。", "examples": {"B": "オーウェンは自分の葬式に遅刻しそうなくらい遅刻魔だけど、一緒に苦楽を共にしてくれた。大切にしてる。", "C": "ダンどこ？あいつ、自分の葬式に遅刻しそう。", "D": "時間にルーズ。"}},
319: {"nativeDefinition": "Exceptionally good or impressive.", "japaneseMeaning": "すごい、別格", "etymology": "something else（別の何か）が並外れて良いことを表す。", "examples": {"B": "スターバックスのカスタマーサービスは別格。いつもお客を笑顔にする。", "C": "たくさんヘッドホン試したけど、このボーズは本当に別格。コスパも最高。", "D": "並外れて良い。"}},
320: {"nativeDefinition": "To earn money to support a household.", "japaneseMeaning": "稼いでくる、生計を支える", "etymology": "bring home the bacon（ベーコンを家に持ち帰る）が生計を支えることを表す。", "examples": {"B": "男には稼いでくるプレッシャーがまだあると思う。", "C": "最近調子悪いけど、今夜全力出せば勝てると信じてる。", "D": "家計を支える。"}},
321: {"nativeDefinition": "To sit down; take a seat.", "japaneseMeaning": "座って、椅子を引いて", "etymology": "pull up a chair（椅子を引く）が席に着くことを表す。", "examples": {"B": "みんな、座って。もうすぐ夕食の準備できる。", "C": "座って一緒に映画見よう。", "D": "座る。"}},
322: {"nativeDefinition": "Presenting only two mutually exclusive options.", "japaneseMeaning": "二者択一、どちらか一方", "etymology": "either-or（どちらか）が二者択一の選択を表す。", "examples": {"B": "キャリアと子育ては二者択一じゃない。両方できる方法がある。", "C": "質か量かってよく聞かれるけど、二者択一じゃないと思う。", "D": "二択。"}},
323: {"nativeDefinition": "To become suddenly very popular.", "japaneseMeaning": "（〜を）席巻する、大ブームになる", "etymology": "take by storm（嵐のように取る）が急速な流行を表す。", "examples": {"B": "あのPPAP、インターネットを席巻して1年くらいで消えた。", "C": "ポケモンGOは数年前世界を席巻した。まだやってる人いる？", "D": "突然非常に人気になる。"}},
324: {"nativeDefinition": "To reveal a secret unintentionally.", "japaneseMeaning": "（秘密を）漏らす、バラす", "etymology": "let the cat out of the bag（猫を袋から出す）が秘密を漏らすことわざ。", "examples": {"B": "ペットのカメを内緒にしてたのに、グレッグが今日バラしちゃった。", "C": "ニーナに辞めること言っちゃダメ。絶対バラす。", "D": "秘密を明かす。"}},
325: {"nativeDefinition": "To stop a habitual behavior.", "japaneseMeaning": "（習慣を）断つ", "etymology": "break a habit（習慣を壊す）が悪癖を止めることを表す。", "examples": {"B": "彼女と同棲する前に喫煙を断ちたい。今しかない。", "C": "仕事後にポテチ食べる習慣、まだ断ててない。良い面もあって、水をたくさん飲むようになった。", "D": "何かをやめる。"}},
326: {"nativeDefinition": "To go out onto the streets; to be released publicly.", "japaneseMeaning": "街に出る、発売される", "etymology": "hit the streets（通りに出る）が公開・発売を表す。", "examples": {"B": "今日はNYの街に出て、NY生活の長所短所を人々に聞く。", "C": "この新製品が街に出るの待ちきれない。", "D": "通りを歩く。発売される。"}},
327: {"nativeDefinition": "To present or consider something in a particular way.", "japaneseMeaning": "（〜を）枠組みで捉える、位置づける", "etymology": "frame（枠）が物事の見方や文脈を設定することを表す。", "examples": {"B": "どう枠組みを設定するかで、ギリギリ合格は運が良かったとも、ちょうどいい勉強量だったとも言える。", "C": "人種差別は存在するけど、全ての問題を人種問題として枠組み設定するのはナンセンス。", "D": "何かを考える。"}},
328: {"nativeDefinition": "To look at someone intensely; to estimate by sight.", "japaneseMeaning": "（〜を）じろじろ見る、目分量で測る", "etymology": "eyeball（眼球）が凝視や目分量を表す。", "examples": {"B": "向かいの男、じろじろ見てきて気持ち悪い。", "C": "レシピがなかったから目分量で調味料入れた。ほぼ完璧だった。", "D": "凝視する。目で大まかに測る。"}},
329: {"nativeDefinition": "A moment of sudden realization or inspiration.", "japaneseMeaning": "ひらめき、電球が点灯した瞬間", "etymology": "light-bulb moment（電球の瞬間）がひらめきを表す。", "examples": {"B": "シャワー中にひらめいた。もう何だったか忘れた。", "C": "ワークショップ中にひらめいて、ロボティクスとプログラミングが情熱だと気づいた。", "D": "突然の気づきやインスピレーションの瞬間。"}},
330: {"nativeDefinition": "Areas of ambiguity rather than clear distinctions.", "japaneseMeaning": "グレーゾーン、曖昧さ", "etymology": "shades of gray（灰色の色合い）が白黒ではない曖昧さを表す。", "examples": {"B": "言語は常に論理的じゃない。グレーゾーンがあることを受け入れないと、永遠にイライラする。", "C": "人生は白黒じゃなくグレーゾーン。だからみんなたどたどしい。", "D": "曖昧さ。"}},
331: {"nativeDefinition": "To suggest an idea to someone informally.", "japaneseMeaning": "（アイデアを）さりげなく提案する", "etymology": "float an idea（アイデアを浮かべる）が試水的に提案することを表す。", "examples": {"B": "このアイデアを提案してくれたのはフィオナ。僕の手柄じゃない。", "C": "ちょっと耳を貸して。アイデアを提案したい。", "D": "誰かにアイデアを提案する。"}},
332: {"nativeDefinition": "Something with both positive and negative aspects.", "japaneseMeaning": "諸刃の剣、両面性がある", "etymology": "double-edged sword（両刃の剣）が一長一短を表す。", "examples": {"B": "自分の意見を主張すべきだけど、嫌われるかも。諸刃の剣。", "C": "インターネットは諸刃の剣。夢を叶える機会をくれる反面、競争も激しくなった。", "D": "プラスとマイナスの両面があるもの。"}},
333: {"nativeDefinition": "The situation is unfairly disadvantageous to someone.", "japaneseMeaning": "不利な状況、勝負が決まってる", "etymology": "deck is stacked against（カードが不利に積まれている）が構造的な不利を表す。", "examples": {"B": "要するに、不利な状況だから、どれだけ頑張っても今年は昇進しない。", "C": "大学行かないと就職で不利。とはいえ不可能じゃない。好きにすればいい。", "D": "状況が誰かにとって不利。"}},
334: {"nativeDefinition": "To understand the hidden or implied meaning.", "japaneseMeaning": "行間を読む", "etymology": "read between the lines（行と行の間を読む）が暗示を理解することを表す。", "examples": {"B": "ビジネス交渉では本音を見せない。行間を読む能力が重要。", "C": "冗談で言ったのに文字通り受け取って怒られた。もっと行間を読んでほしい。", "D": "隠された意味を理解する。"}},
335: {"nativeDefinition": "To end someone's suffering or anxiety.", "japaneseMeaning": "（人を）苦しみから解放する", "etymology": "put out of one's misery（苦しみから出す）が安らかにさせることを表す。", "examples": {"B": "終末期の犬の安楽死は議論があるけど、選択肢の一つであるべき。", "C": "結果来月まで出ないの？もう苦しい、早く教えて。", "D": "誰かを苦しみから解放する。"}},
336: {"nativeDefinition": "A situation that repeats monotonously like the movie Groundhog Day.", "japaneseMeaning": "グラウンドホッグデイ状態、同じ繰り返し", "etymology": "映画『グラウンドホッグ・デー』から、同じ日の繰り返しを表す。", "examples": {"B": "最近やってること、仕事・食事・睡眠の繰り返し。グラウンドホッグデイみたい。", "C": "この動画、同じ内容を違う切り口で何度も出してる。グラウンドホッグデイ。", "D": "同じ日が繰り返される。"}},
337: {"nativeDefinition": "Frozen in fear or confusion.", "japaneseMeaning": "鹿がヘッドライトを見つめるように、固まる", "etymology": "deer in the headlights（ヘッドライトを見る鹿）が恐怖で固まることを表す。", "examples": {"B": "面接官が curveball を投げてきて、頭が真っ白。鹿がヘッドライトを見つめるみたいだった。", "C": "キャシー、プレゼン中にオーラの話をした時、鹿がヘッドライトを見つめるみたいだった。", "D": "恐怖で固まる。"}},
338: {"nativeDefinition": "A fundamental component of something larger.", "japaneseMeaning": "構成要素、基礎ブロック", "etymology": "building block（積み木）が基本要素を表す。", "examples": {"B": "コンピテンスの重要な構成要素の一つは、たくさんの成功体験。", "C": "成功の重要な構成要素は、戦略的思考と何があっても前進する能力。", "D": "基本的な構成要素。"}},
339: {"nativeDefinition": "To punish someone as a warning to others.", "japaneseMeaning": "（人を）見せしめにする", "etymology": "make an example of（例にする）が警告的な処罰を表す。", "examples": {"B": "マネージャー、今日は厳しかった。みんなの前で僕を見せしめにした。", "C": "去年、証券法違反で逮捕されたけど、強い証拠はなかった。検察は見せしめにしたかった。", "D": "他者への警告として罰する。"}},
340: {"nativeDefinition": "To remain successful or popular over a long time.", "japaneseMeaning": "時の試練に耐える", "etymology": "stand the test of time（時間の試練に立つ）が長年愛されることを表す。", "examples": {"B": "スタンスミスは時の試練に耐えるadidasの定番スニーカー。", "C": "マイケル・ジャクソンの音楽が時の試練に耐えてるのはすごい。", "D": "長期間成功し続ける。"}},
341: {"nativeDefinition": "The more people involved, the better.", "japaneseMeaning": "多ければ多いほど楽しい", "etymology": "the more the merrier（多いほど陽気）が人数が多いほど良いことを表す。", "examples": {"B": "友達も連れてきて。多ければ多いほど楽しい。", "C": "人が多すぎる？まあ、多ければ多いほど楽しいかな。", "D": "人が多いほど楽しい。"}},
342: {"nativeDefinition": "An unfair campaign to blame or punish someone.", "japaneseMeaning": "魔女狩り、不当な糾弾", "etymology": "witch hunt（魔女狩り）が不当な追及を表す。", "examples": {"B": "SNSの魔女狩り、人類の未来が心配。", "C": "香港で中国政府がやってるのは、愛国心が足りない人への魔女狩り。", "D": "不当で非合理的な非難。"}},
343: {"nativeDefinition": "A person considered flawed or undesirable.", "japaneseMeaning": "傷物、使い物にならない人", "etymology": "damaged goods（傷ついた商品）が価値のない人を表す。", "examples": {"B": "4週間プロジェクトにアサインされない。回りくどい方法で傷物扱いされてる？", "C": "成長し続けない人は、この厳しい職場では傷物になりやすい。", "D": "望まれない不適格な人。"}},
344: {"nativeDefinition": "To deliberately provoke someone's anger.", "japaneseMeaning": "（人を）怒らせる、カンを刺す", "etymology": "get a rise out of（反応を引き出す）が意図的に挑発することを表す。", "examples": {"B": "明らかに挑発してる。怒らせようとしてる。ブロックする。", "C": "ごめん、冗談だった。怒らせようとしてたわけじゃない。", "D": "意図的に怒らせる。"}},
345: {"nativeDefinition": "Be honest; speaking frankly.", "japaneseMeaning": "正直に言うと、本音を言うなら", "etymology": "be real（本物であれ）が率直に話すスラング。", "examples": {"B": "ちょっと正直に言っていい？実はお酒嫌い。みんなが飲むから付き合ってる。", "C": "正直に言うと、多くの人は事実と意見を区別できない。だからフェイクニュースが広がる。", "D": "正直である。"}},
346: {"nativeDefinition": "Just in time; at the last possible moment.", "japaneseMeaning": "間一髪、ギリギリ間に合った", "etymology": "in the nick of time（時間の切れ目に）が間一髪を表す。", "examples": {"B": "閉店数分前に間一髪で店に着いた。", "C": "空港に間一髪で着いた。良かった。", "D": "ぎりぎり間に合って。"}},
347: {"nativeDefinition": "To have a grievance that needs settling.", "japaneseMeaning": "（〜と）清算がある、恨みがある", "etymology": "score to settle（決着をつける点数）が未解決の問題を表す。", "examples": {"B": "ジョーカーとの決着をつけたかった。ついに決着つけた。", "C": "なんであの写真送ったの？清算があるの？", "D": "誰かに復讐する。"}},
348: {"nativeDefinition": "Without knowing or understanding.", "japaneseMeaning": "（〜も）知らず、気づかない", "etymology": "none the wiser（少しも賢くない）が何も知らない状態を表す。", "examples": {"B": "AIはパンドラの箱を開けた。でも多くの人はまだ気づいてない。", "C": "妹と友達のチャット30分聞いてるけど、何の話か全然わからない。", "D": "理解していない。"}},
349: {"nativeDefinition": "In a similar way or style.", "japaneseMeaning": "同じ路線で、同様に", "etymology": "in the same vein（同じ血管で）が同様の方向性を表す。", "examples": {"B": "猫の恩返しは他のジブリ作品とは違う路線だけど、面白い映画。", "C": "子供の頃コミック収集が好きで、同様にアニメにもハマってた。", "D": "似ている。同様に。"}},
350: {"nativeDefinition": "In a situation too difficult to handle.", "japaneseMeaning": "手に負えない、能力を超えている", "etymology": "in over one's head（頭より深い）が手に負えない状態を表す。", "examples": {"B": "2週間でマラソン準備できると思ったけど、明らかに手に負えない。", "C": "新しい仕事、良いスタートだったけど、今は手に負えない。何やってるかわからない。", "D": "能力を超えている。"}},
351: {"nativeDefinition": "When one thing happens, many similar things follow.", "japaneseMeaning": "泣きっ面に蜂、祸不单行", "etymology": "when it rains, it pours（雨が降れば土砂降り）が不幸や幸運の連鎖を表す。", "examples": {"B": "エアコン壊れた、冷蔵庫の明かり消えた、車も動かない。祸不单行。", "C": "昇給、新彼女、来週休暇。幸運も祸不单行。", "D": "良いことも悪いことも続けて起こる。"}},
352: {"nativeDefinition": "An unexpected twist or surprise.", "japaneseMeaning": "どんでん返し、プロットツイスト", "etymology": "plot twist（プロットのねじれ）が物語のどんでん返しを表す。", "examples": {"B": "宇宙人信じる？どんでん返し、僕宇宙人。", "C": "明日2つの課題提出。どんでん返し、まだ始めてない。", "D": "サプライズ！"}},
353: {"nativeDefinition": "To be the most extreme example (best or worst).", "japaneseMeaning": "（〜の）极致だ、最高に〜", "etymology": "take the cake（ケーキを取る）が最たる例を表す。", "examples": {"B": "ビルは変な決断いっぱいしたけど、ヘビをペットにするのは极致。", "C": "ケンのタトゥー、极致だ。ピカチュウが背中にある。", "D": "最悪／最高である。"}},
354: {"nativeDefinition": "Finally, but equally important.", "japaneseMeaning": "最後に、そして忘れずに", "etymology": "last but not least（最後だが最も重要ではない）が締めくくりの表現。", "examples": {"B": "最後に、今日のファシリテーター、ダグラス・カペルさんを紹介します。", "C": "最後に、今日来てくれてありがとう。以上です。次回もお会いしましょう。", "D": "最後に、しかし同等に重要。"}},
355: {"nativeDefinition": "A ruthlessly competitive environment.", "japaneseMeaning": "弱肉強食の世界", "etymology": "dog-eat-dog world（犬が犬を食べる世界）が残酷な競争社会を表す。", "examples": {"B": "この業界は弱肉強食。優しさは通用しない。", "C": "NYは弱肉強食の世界。生き残るにはタフでないと。", "D": "残酷に競争的な環境。"}},
356: {"nativeDefinition": "Be quiet; stop talking.", "japaneseMeaning": "黙れ、口をつぐんで", "etymology": "put a sock in it（靴下を入れろ）が口を封じる口語表現。", "examples": {"B": "うるさい、黙れ。", "C": "もういい、口をつぐんで。", "D": "静かにしろ。"}},
357: {"nativeDefinition": "Wealth gives power and influence.", "japaneseMeaning": "金の力は偉大", "etymology": "money talks（金が話す）が金の力を表すことわざ。", "examples": {"B": "金の力は偉大。金があれば何でもできる。", "C": "政治では金の力が偉大。", "D": "お金が物を言う。"}},
358: {"nativeDefinition": "Progress has already begun and cannot easily be stopped.", "japaneseMeaning": "すでに動き出している、歯車は回り始めた", "etymology": "wheels in motion（動いている車輪）が始まったプロセスを表す。", "examples": {"B": "もう動き出してる。止めるのは難しい。", "C": "計画はすでに動き出してる。後戻りできない。", "D": "すでに進行中。"}},
359: {"nativeDefinition": "To take the morally superior approach.", "japaneseMeaning": "高潔な道を取る", "etymology": "take the high road（高い道を取る）が道徳的に正しい選択を表す。", "examples": {"B": "同じレベルに下がらず、高潔な道を取った。", "C": "復讐する代わりに高潔な道を選んだ。", "D": "道徳的に優れたアプローチを取る。"}},
360: {"nativeDefinition": "To sell very quickly and in large quantities.", "japaneseMeaning": "飛ぶように売れる", "etymology": "sell like hotcakes（ホットケーキのように売れる）が大ヒット販売を表す。", "examples": {"B": "新製品、飛ぶように売れてる。", "C": "この本、飛ぶように売れた。", "D": "非常に速く大量に売れる。"}},
361: {"nativeDefinition": "To clearly show or indicate something.", "japaneseMeaning": "物語る、雄弁に語る", "etymology": "speak volumes（大量に語る）が雄弁に物語ることを表す。", "examples": {"B": "彼の行動は雄弁に物語ってる。", "C": "沈黙が雄弁に物語る。", "D": "明確に示す。"}},
362: {"nativeDefinition": "Used to emphasize something strongly.", "japaneseMeaning": "〜と強調してもしすぎない", "etymology": "can't emphasize enough（十分に強調できない）が強調の表現。", "examples": {"B": "どれだけ強調してもしすぎないくらい、これは重要。", "C": "早めに予約することを、どれだけ強調してもしすぎない。", "D": "強調しすぎることはない。"}},
363: {"nativeDefinition": "Something that should definitely be avoided.", "japaneseMeaning": "絶対ダメ、大タブー", "etymology": "big no-no（大きなダメ）がタブーを表すスラング。", "examples": {"B": "遅刻は絶対ダメ。", "C": "上司に嘘つくのは大タブー。", "D": "避けるべきこと。"}},
364: {"nativeDefinition": "To have good intentions despite bad outcomes.", "japaneseMeaning": "悪気はない、良かれと思って", "etymology": "mean well（良い意味で）が善意を表す。", "examples": {"B": "悪気はないから許して。良かれと思って言った。", "C": "彼女は悪気なくアドバイスしてる。", "D": "良い意図を持つ。"}},
365: {"nativeDefinition": "Difficult, dangerous, or complicated.", "japaneseMeaning": "厄介な、難しい", "etymology": "hairy（毛深い）が口語で厄介・危険を表す。", "examples": {"B": "この交渉、厄介になりそう。", "C": "状況が厄介になってきた。", "D": "難しい。"}},
366: {"nativeDefinition": "To have no valid argument or defense.", "japaneseMeaning": "反論の余地がない", "etymology": "not have a leg to stand on（立つ足がない）が根拠がないことを表す。", "examples": {"B": "その主張、反論の余地がない。", "C": "彼は反論の余地がない立場。", "D": "正当な根拠がない。"}},
367: {"nativeDefinition": "In a deadlock with no progress.", "japaneseMeaning": "膠着状態", "etymology": "stalemate（ステイルメイト）がチェス用語から交渉の行き詰まり。", "examples": {"B": "交渉は膠着状態。", "C": "両者膠着、動きがない。", "D": "行き詰まり。"}},
368: {"nativeDefinition": "Hurry up; drive faster.", "japaneseMeaning": "急いで、スピード上げて", "etymology": "step on it（アクセル踏む）が急ぐことを表す。", "examples": {"B": "急いで！遅れる。", "C": "スピード上げて。間に合わない。", "D": "急ぐ。"}},
369: {"nativeDefinition": "A hidden motive.", "japaneseMeaning": "裏の意図、下心", "etymology": "ulterior motive（奥の動機）が隠れた目的を表す。", "examples": {"B": "彼には裏の意図がある。", "C": "下心が見え見え。", "D": "隠された動機。"}},
370: {"nativeDefinition": "To fail; to go bankrupt; a police raid.", "japaneseMeaning": "破産する、失敗する", "etymology": "bust（破裂する）が破産や失敗を表す。", "examples": {"B": "ビジネスが破産した。", "C": "計画は失敗。", "D": "破産する。"}},
371: {"nativeDefinition": "To investigate or look around secretly.", "japaneseMeaning": "（こっそり）探る、詮索する", "etymology": "snoop around（嗅ぎ回る）がこっそり調査することを表す。", "examples": {"B": "彼女の部屋をこっそり探った。", "C": "隣人のことを詮索するな。", "D": "秘密裏に調査する。"}},
372: {"nativeDefinition": "In one's imagination or memory.", "japaneseMeaning": "心の目で、想像の中で", "etymology": "mind's eye（心の目）が想像や記憶を表す。", "examples": {"B": "心の目でその光景が浮かぶ。", "C": "心の目で思い出す。", "D": "想像の中で。"}},
373: {"nativeDefinition": "To repair a relationship or fix something.", "japaneseMeaning": "（関係を）修復する", "etymology": "patch up（継ぎ接ぎする）が関係修復を表す。", "examples": {"B": "喧嘩したけど関係修復した。", "C": "二人、関係修復中。", "D": "何かを修復する。"}},
374: {"nativeDefinition": "To ease someone's guilty feelings.", "japaneseMeaning": "（人の）良心を楽にする", "etymology": "ease conscience（良心を楽にする）が罪悪感を和らげることを表す。", "examples": {"B": "寄付して良心を楽にした。", "C": "謝罪して彼女の良心を楽にした。", "D": "罪悪感を和らげる。"}},
375: {"nativeDefinition": "In modern times; nowadays.", "japaneseMeaning": "現代では、今の時代", "etymology": "in this day and age（この日と時代に）が現代を強調する表現。", "examples": {"B": "現代では、SNSなしの生活は考えられない。", "C": "今の時代、それは当たり前。", "D": "現代において。"}},
376: {"nativeDefinition": "To leave; to go toward the exit.", "japaneseMeaning": "出口に向かう、退場する", "etymology": "head for the exit（出口に向かう）が退場することを表す。", "examples": {"B": "彼は出口に向かった。", "C": "会議から退場した。", "D": "去る。"}},
377: {"nativeDefinition": "A situation where one's gain is another's loss.", "japaneseMeaning": "ゼロサムゲーム", "etymology": "zero-sum game（ゼロ和ゲーム）がゲーム理論用語。", "examples": {"B": "これはゼロサムゲームじゃない。", "C": "政治はしばしばゼロサムゲーム。", "D": "一方の得が他方の損。"}},
378: {"nativeDefinition": "A person who seems older and wiser than their age.", "japaneseMeaning": "オールドソウル、老成した人", "etymology": "old soul（古い魂）が年齢以上に成熟した人を表す。", "examples": {"B": "彼女はオールドソウル。20代なのに賢い。", "C": "子供の頃からオールドソウルだった。", "D": "年齢以上に成熟した人。"}},
379: {"nativeDefinition": "A compilation of best moments.", "japaneseMeaning": "ハイライトリール、ベストシーン集", "etymology": "highlight reel（ハイライトフィルム）が最高の瞬間の集大成。", "examples": {"B": "キャリアのハイライトリール。", "C": "今年のベストシーン集。", "D": "最高の瞬間の集まり。"}},
380: {"nativeDefinition": "To create excitement or controversy.", "japaneseMeaning": "ざわつかせる、物議を醸す", "etymology": "cause a stir（騒ぎを起こす）が物議を醸すことを表す。", "examples": {"B": "その発言が物議を醸した。", "C": "新しい政策がざわつかせてる。", "D": "騒ぎを起こす。"}},
381: {"nativeDefinition": "To appear unexpectedly, especially in large numbers.", "japaneseMeaning": "（突然）現れる、巣食い出す", "etymology": "come out of the woodwork（木材から出てくる）が突然現れることを表す。", "examples": {"B": "賞金が出ると、突然現れる人が増える。", "C": "問題が起きると、批評家が巣食い出す。", "D": "予期せず現れる。"}},
382: {"nativeDefinition": "Both parties share responsibility.", "japaneseMeaning": "双方に責任がある、二人でタンゴ", "etymology": "it takes two to tango（タンゴには二人必要）が双方の責任を表す。", "examples": {"B": "喧嘩には双方に原因がある。", "C": "離婚は双方の責任。", "D": "両方が関与している。"}},
383: {"nativeDefinition": "To promote or publicize something enthusiastically.", "japaneseMeaning": "（〜を）宣伝する、大々的に打ち出す", "etymology": "bang the drum（太鼓を叩く）が宣伝することを表す。", "examples": {"B": "新製品を宣伝してる。", "C": "環境問題を宣伝し続ける。", "D": "宣伝する。"}},
384: {"nativeDefinition": "To hold court; to be the center of attention.", "japaneseMeaning": "中心に座る、注目を集める", "etymology": "hold court（宮廷を開く）が注目の的になることを表す。", "examples": {"B": "彼はいつもパーティーの中心。", "C": "彼女が注目を集めて話してる。", "D": "注目の中心にいる。"}},
385: {"nativeDefinition": "To be in poor condition due to age or wear.", "japaneseMeaning": "ボロボロ、昔は良かった", "etymology": "seen better days（より良い日を見た）がかつては良かったものを表す。", "examples": {"B": "この車、ボロボロ。", "C": "建物は昔は良かった。", "D": "かつては良い状態だった。"}},
386: {"nativeDefinition": "Perfectly suited for someone or something.", "japaneseMeaning": "（〜に）ぴったりの、オーダーメイド", "etymology": "tailor-made（仕立てられた）が完璧に合うことを表す。", "examples": {"B": "この仕事、彼女にぴったり。", "C": "彼にぴったりのプレゼント。", "D": "完璧に合う。"}},
387: {"nativeDefinition": "To lose in a competition or comparison.", "japaneseMeaning": "（比較で）負ける、劣る", "etymology": "come off second best（二番目に終わる）が劣ることを表す。", "examples": {"B": "比較で負けた。", "C": "競争で劣った。", "D": "負ける。"}},
388: {"nativeDefinition": "To obstruct or hinder someone.", "japaneseMeaning": "（人の）邪魔をする", "etymology": "get in one's way（道に入る）が妨害することを表す。", "examples": {"B": "邪魔しないで。", "C": "彼が進路の邪魔をした。", "D": "妨げる。"}},
389: {"nativeDefinition": "Including flaws and imperfections; completely.", "japaneseMeaning": "欠点も含めて、ありのまま", "etymology": "warts and all（イボも全部）が欠点も含めてを表す。", "examples": {"B": "欠点も含めて愛してる。", "C": "ありのまま受け入れる。", "D": "欠点も含めて。"}},
390: {"nativeDefinition": "To act boldly without worrying about risks.", "japaneseMeaning": "思い切ってやる、リスクを恐れない", "etymology": "throw caution to the wind（注意を風に投げる）が大胆に行動することを表す。", "examples": {"B": "思い切って告白した。", "C": "リスクを恐れず挑戦した。", "D": "大胆に行動する。"}},
391: {"nativeDefinition": "To prevent something from succeeding or progressing.", "japaneseMeaning": "（〜を）脱線させる、台無しにする", "etymology": "derail（脱線する）が計画を妨害することを表す。", "examples": {"B": "政治家がレッドヘリングで会話を脱線させるのが嫌い。", "C": "この電話で週末の計画が台無しになった。", "D": "何かの成功や進展を妨げる。"}},
392: {"nativeDefinition": "To be much better than someone else.", "japaneseMeaning": "（人を）大差で上回る", "etymology": "run circles around（周りを走り回る）が圧倒的に優れることを表す。", "examples": {"B": "内装ではメルセデス・ベンツが他社を大差で上回ってる。", "C": "料理は父が僕を大差で上回る。でも皿洗いは僕がやる。", "D": "誰かより優れている。"}},
393: {"nativeDefinition": "To try something cautiously to see if it works.", "japaneseMeaning": "様子を見る、試してみる", "etymology": "test the waters（水を試す）が慎重に試すことを表す。", "examples": {"B": "元カノと戻りたい？メッセージ送って様子見しよう。", "C": "eBayに1200ドルで出品して様子見。誰も買わないと思うけど。", "D": "成功の可能性を確かめる。"}},
394: {"nativeDefinition": "To enjoy something thoroughly.", "japaneseMeaning": "（〜を）存分に楽しむ", "etymology": "have a field day（野外日）が大いに楽しむことを表す。", "examples": {"B": "この人の仕草、すごく面白い。ジェフのクリエイターが存分に楽しむだろう。", "C": "大統領がタイポ修正したけど、SNSはすでに存分に楽しんでる。", "D": "何かから大いに楽しむ。"}},
395: {"nativeDefinition": "Someone is not foolish or easily deceived.", "japaneseMeaning": "（人は）バカじゃない", "etymology": "wasn't born yesterday（昨日生まれたわけじゃない）が騙されないことを表す。", "examples": {"B": "説明が筋通らない。年利30%の口座があると信じると思った？バカじゃない。", "C": "バカじゃないよ。宿題を犬が食べたなんて信じるわけない。", "D": "そんなにバカじゃない。"}},
396: {"nativeDefinition": "Pretending to dislike something one cannot have.", "japaneseMeaning": "酸っぱいブドウ、負け惜しみ", "etymology": "sour grapes（酸っぱいブドウ）がイソップ寓話から負け惜しみ。", "examples": {"B": "彼女と付き合えないから、酸っぱいブドウって言ってる。", "C": "落選したから、酸っぱいブドウ。", "D": "手に入らないものを嫌いだと言う。"}},
397: {"nativeDefinition": "Requiring a lot of attention and effort.", "japaneseMeaning": "手のかかる、世話が必要", "etymology": "high-maintenance（メンテナンスが多い）が手間がかかる人を表す。", "examples": {"B": "彼女、手のかかる人。", "C": "この車、メンテナンスが大変。", "D": "多くの注意と努力を必要とする。"}},
398: {"nativeDefinition": "Forgotten when not visible.", "japaneseMeaning": "去る者日々に疎し", "etymology": "out of sight, out of mind（見えなければ心にもない）のことわざ。", "examples": {"B": "遠くに住む親友、去る者日々に疎し。", "C": "見えなくなると忘れる。", "D": "見えなければ忘れる。"}},
399: {"nativeDefinition": "A characteristic shared by family members.", "japaneseMeaning": "家系に受け継がれる", "etymology": "run in the family（家族に走る）が遺伝的特徴を表す。", "examples": {"B": "うちはみんな背が高い。家系に受け継がれてる。", "C": "心臓病は家系に受け継がれてる。", "D": "家族に共通する特徴。"}},
400: {"nativeDefinition": "To bully or tease someone.", "japaneseMeaning": "（人を）いじめる、からかう", "etymology": "pick on（選んで攻める）が弱者を狙うことを表す。", "examples": {"B": "弟をいじめるな。", "C": "学校でいじめられた。", "D": "誰かをいじめる。"}},
}
